import { useState, useEffect } from "react";
import "./InternalPortal.css";

function InternalPortal() {
  const [jobs, setJobs] = useState([]);
  const [title, setTitle] = useState("");
  const [department, setDepartment] = useState("");
  const [desc, setDesc] = useState("");
  const [editId, setEditId] = useState(null);

  /* =========================
        LOAD JOBS
     ========================= */
  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem("internalJobs")) || [];
    setJobs(saved);
  }, []);

  /* =========================
        SAVE HELPER
     ========================= */
  const saveJobs = (updated) => {
    setJobs(updated);
    localStorage.setItem("internalJobs", JSON.stringify(updated));
  };

  /* =========================
        CREATE / UPDATE
     ========================= */
  const handlePost = () => {
    if (!title.trim() || !department.trim() || !desc.trim()) {
      alert("Please fill all fields");
      return;
    }

    if (editId !== null) {
      const updated = jobs.map((job) =>
        job.id === editId ? { ...job, title, department, desc } : job
      );

      saveJobs(updated);
      alert("Job Updated Successfully");
      setEditId(null);
    } else {
      const newJob = {
        id: Date.now(),
        title,
        department,
        desc,
      };

      const updated = [...jobs, newJob];
      saveJobs(updated);
      alert("Job Posted Successfully");
    }

    setTitle("");
    setDepartment("");
    setDesc("");
  };

  /* =========================
        DELETE
     ========================= */
  const handleDelete = (id) => {
    if (!window.confirm("Are you sure you want to delete this job?")) return;
    const updated = jobs.filter((job) => job.id !== id);
    saveJobs(updated);
  };

  /* =========================
        EDIT
     ========================= */
  const handleEdit = (job) => {
    setEditId(job.id);
    setTitle(job.title);
    setDepartment(job.department);
    setDesc(job.desc);
  };

  return (
    <div className="internal-portal-page">
      <h2>Internal Job Portal</h2>

      {/* ================= FORM CARD ================= */}
      <div className="internal-portal-form-card">
        <div className="internal-portal-form-row">
          <input
            type="text"
            placeholder="Job Title e.g Senior Developer"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
          />

          <input
            type="text"
            placeholder="Department"
            value={department}
            onChange={(e) => setDepartment(e.target.value)}
          />

          <input
            type="text"
            placeholder="Short Job Description"
            value={desc}
            onChange={(e) => setDesc(e.target.value)}
          />

          <button type="button" onClick={handlePost}>
            {editId ? "Update Job" : "Post Job"}
          </button>
        </div>
      </div>

      {/* ================= TABLE CARD ================= */}
      <div className="internal-portal-table-card">
        <table className="internal-portal-table">
          <thead>
            <tr>
              <th>S.No</th>
              <th>Job Title</th>
              <th>Department</th>
              <th>Description</th>
              <th>Action</th>
            </tr>
          </thead>

          <tbody>
            {jobs.length === 0 ? (
              <tr>
                <td colSpan="5" className="internal-no-data">
                  No Internal Jobs Posted Yet
                </td>
              </tr>
            ) : (
              jobs.map((job, index) => (
                <tr key={job.id}>
                  <td>{index + 1}</td>
                  <td>{job.title}</td>
                  <td>{job.department}</td>
                  <td>{job.desc}</td>
                  <td>
                    <div className="internal-portal-actions">
                      <button
                        type="button"
                        className="internal-portal-edit"
                        onClick={() => handleEdit(job)}
                      >
                        Edit
                      </button>

                      <button
                        type="button"
                        className="internal-portal-delete"
                        onClick={() => handleDelete(job.id)}
                      >
                        Delete
                      </button>
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default InternalPortal;
